// menu.js - كود واحد كامل
import { useState, useEffect } from "react";

export default function Menu() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [textIndex, setTextIndex] = useState(0);
  
  const texts = ["مرحباً بكم", "أهلاً وسهلاً", "تفضلوا", "استمتعوا"];

  // 4 كاردات فقط - أحجام كبيرة
  const cards = [
    { id: 1, name: "شيشة", icon: "💨", color: "#ff6b6b", size: 180, top: "10%", left: "3%", rotate: -8, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
    { id: 2, name: "أكل", icon: "🍔", color: "#4ecdc4", size: 160, top: "60%", left: "2%", rotate: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
    { id: 3, name: "مشروبات", icon: "🥤", color: "#45b7d1", size: 170, top: "15%", right: "3%", rotate: -5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
    { id: 4, name: "ديسار", icon: "🍰", color: "#f9ca24", size: 165, top: "65%", right: "2%", rotate: 7, image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" }
  ];

  // تغيير النص في المنتصف
  useEffect(() => {
    const interval = setInterval(() => {
      setTextIndex((prev) => (prev + 1) % texts.length);
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  // حركة الماوس
  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 60,
        y: (e.clientY / window.innerHeight - 0.5) * 60
      });
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  // دالة عند الضغط على كارد
  const handleCardClick = (cardName) => {
    alert(`لقد اخترت: ${cardName}`);
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, #0f0c29, #302b63, #24243e)",
      position: "relative",
      overflow: "hidden",
      fontFamily: "sans-serif"
    }}>
      
      {/* خلفية متحركة */}
      <div style={{
        position: "absolute",
        width: "100%",
        height: "100%",
        background: "radial-gradient(circle at 50% 50%, rgba(34,197,94,0.1) 0%, transparent 70%)",
        pointerEvents: "none"
      }}></div>

      {/* الكاردات الأربعة - في الخلفية (زائد أقل) */}
      {cards.map((card) => (
        <div
          key={card.id}
          onClick={() => handleCardClick(card.name)}
          style={{
            position: "fixed",
            top: card.top,
            left: card.left,
            right: card.right,
            transform: `
              translate(
                ${mousePosition.x * (card.id % 2 === 0 ? 0.5 : -0.4)}px, 
                ${mousePosition.y * (card.id % 2 === 0 ? -0.4 : 0.5)}px
              ) 
              rotate(${card.rotate}deg)
            `,
            transition: "transform 0.2s ease-out",
            zIndex: 5,
            cursor: "pointer"
          }}
        >
          <div style={{
            background: `linear-gradient(135deg, ${card.color}, ${card.color}aa)`,
            width: `${card.size}px`,
            padding: "25px 15px",
            borderRadius: "35px",
            textAlign: "center",
            boxShadow: "0 25px 50px rgba(0,0,0,0.4)",
            backdropFilter: "blur(10px)",
            border: "2px solid rgba(255,255,255,0.3)",
            transition: "all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275)"
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = `scale(1.08) rotate(${card.rotate + 5}deg)`;
            e.currentTarget.style.boxShadow = "0 35px 60px rgba(0,0,0,0.5)";
            e.currentTarget.style.border = "2px solid rgba(34,197,94,0.8)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "scale(1) rotate(0deg)";
            e.currentTarget.style.boxShadow = "0 25px 50px rgba(0,0,0,0.4)";
            e.currentTarget.style.border = "2px solid rgba(255,255,255,0.3)";
          }}
          >
            <img 
              src={card.image} 
              alt={card.name} 
              style={{ 
                width: "80px", 
                height: "80px", 
                marginBottom: "12px", 
                filter: "drop-shadow(2px 4px 10px black)" 
              }} 
            />
            <h3 style={{ 
              color: "white", 
              margin: "10px 0 5px", 
              fontSize: "1.6rem", 
              fontWeight: "bold" 
            }}>{card.name}</h3>
            <span style={{ fontSize: "2.5rem" }}>{card.icon}</span>
          </div>
        </div>
      ))}

      {/* النص المتحرك في المنتصف - فوق الكاردات */}
      <div style={{
        position: "fixed",
        top: "50%",
        left: "50%",
        transform: `translate(-50%, -50%) translate(${mousePosition.x * 0.2}px, ${mousePosition.y * 0.2}px)`,
        textAlign: "center",
        zIndex: 20,
        transition: "transform 0.15s ease-out",
        pointerEvents: "none" // يسمح بالضغط على الكاردات من خلال النص
      }}>
        <div style={{
          background: "rgba(0,0,0,0.65)",
          backdropFilter: "blur(30px)",
          padding: "50px 85px",
          borderRadius: "70px",
          border: "2px solid rgba(34,197,94,0.6)",
          boxShadow: "0 0 100px rgba(34,197,94,0.25), 0 25px 50px rgba(0,0,0,0.4)"
        }}>
          <h1 style={{
            fontSize: "4rem",
            fontWeight: "bold",
            background: "linear-gradient(135deg, #ffffff, #22c55e, #4ade80)",
            WebkitBackgroundClip: "text",
            WebkitTextFillColor: "transparent",
            margin: 0,
            letterSpacing: "3px"
          }}>
            {texts[textIndex]}
          </h1>
          <p style={{ color: "#ddd", marginTop: "18px", fontSize: "1.2rem", letterSpacing: "1px" }}>
            ✨ اختر ما تفضله ✨
          </p>
          <div style={{
            width: "100px",
            height: "3px",
            background: "linear-gradient(90deg, #22c55e, #4ade80, transparent)",
            margin: "22px auto 0",
            borderRadius: "10px"
          }}></div>
        </div>
      </div>

      {/* نص سفلي */}
      <div style={{
        position: "fixed",
        bottom: "20px",
        left: "0",
        right: "0",
        textAlign: "center",
        color: "rgba(255,255,255,0.3)",
        fontSize: "12px",
        zIndex: 30,
        pointerEvents: "none"
      }}>
        ✨ اضغط على أي كارد لاختيار المنتج ✨
      </div>
    </div>
  );
}
